/* Reset & basic typography */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}
body {
    font-family: system-ui, -apple-system, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    line-height: 1.6;
    color: #2c2c2c;
    background-color: #f5f9f5;
    scroll-behavior: smooth;
}

/* Navigation */
.navbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    background-color: #2e7d32; /* deep green */
    color: #fff;
    padding: 0.5rem 1rem;
    position: sticky;
    top: 0;
    z-index: 1000;
}
.nav-brand {
    font-size: 1.5rem;
    font-weight: bold;
}
.nav-links {
    list-style: none;
    display: flex;
    gap: 1rem;
}
.nav-links a {
    color: #fff;
    text-decoration: none;
    font-weight: 500;
}
.nav-toggle {
    display: none;
    background: none;
    border: none;
    cursor: pointer;
}
.hamburger, .hamburger::before, .hamburger::after {
    content: '';
    display: block;
    width: 25px;
    height: 3px;
    background-color: #fff;
    margin: 5px 0;
    transition: all 0.3s ease;
}

/* Hero */
.hero {
    background: linear-gradient(rgba(46,125,50,0.8), rgba(46,125,50,0.8)), url('https://via.placeholder.com/1200x600?text=Frog+Background') center/cover no-repeat;
    color: #fff;
    text-align: center;
    padding: 6rem 1rem;
}
.hero h1 {
    font-size: 2.5rem;
    margin-bottom: 1rem;
}
.hero p {
    font-size: 1.2rem;
    margin-bottom: 2rem;
}
.cta-button {
    background-color: #ffca28; /* amber */
    color: #2c2c2c;
    padding: 0.75rem 1.5rem;
    border: none;
    border-radius: 4px;
    text-decoration: none;
    font-weight: bold;
    transition: background 0.3s;
}
.cta-button:hover {
    background-color: #ffb300;
}

/* Sections */
section {
    padding: 4rem 1rem;
    max-width: 1200px;
    margin: 0 auto;
}
section h2 {
    text-align: center;
    margin-bottom: 2rem;
    font-size: 2rem;
    color: #2e7d32;
}

/* Card Grid */
.card-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
    gap: 1.5rem;
}
.card {
    background-color: #fff;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
    transition: transform 0.3s;
}
.card:hover {
    transform: translateY(-5px);
}
.card img {
    width: 100%;
    height: auto;
    display: block;
}
.card h3 {
    padding: 0.5rem 1rem;
    font-size: 1.25rem;
    color: #2c2c2c;
}
.card p {
    padding: 0 1rem 1rem;
    font-size: 0.95rem;
    color: #555;
}

/* Facts */
.fact-list {
    list-style: disc inside;
    max-width: 800px;
    margin: 0 auto;
    font-size: 1.1rem;
    line-height: 1.8;
    color: #333;
}

/* Awesome Section */
.awesome p {
    max-width: 800px;
    margin: 0 auto;
    font-size: 1.1rem;
    line-height: 1.6;
    text-align: center;
}

/* Footer */
.footer {
    background-color: #2e7d32;
    color: #fff;
    text-align: center;
    padding: 1rem;
    font-size: 0.9rem;
}

/* Responsive Hamburger */
@media (max-width: 768px) {
    .nav-links {
        position: absolute;
        top: 100%;
        left: 0;
        right: 0;
        background-color: #2e7d32;
        flex-direction: column;
        display: none;
    }
    .nav-links.show {
        display: flex;
    }
    .nav-toggle {
        display: block;
    }
}
```
