            top: 0;
            left: 50px;
        }

        .lotus-petal:nth-child(2) {
            top: 25px;
            left: 75px;
        }

        .lotus-petal:nth-child(3) {
            top: 50px;
            left: 50px;
        }

        .lotus-petal:nth-child(4) {
            top: 25px;
            left: 25px;
        }

        .lotus-center {
            width: 30px;
            height: 30px;
            background: #ffd700;
